const { iniInternals } = require("bun:internal-for-testing");
const { parse } = iniInternals;
import { describe, expect, it, test } from "bun:test";
import { bunEnv, bunExe, tempDirWithFiles } from "harness";

describe("Bun.INI", () => {
  describe("parse", () => {
    test("basic key=value pairs", () => {
      expect(Bun.INI.parse("name = Alice\nage = 30")).toEqual({ name: "Alice", age: 30 });
    });

    test("sections become nested objects", () => {
      const input = `
name = root

[database]
host = localhost
port = 5432
`;
      expect(Bun.INI.parse(input)).toEqual({
        name: "root",
        database: { host: "localhost", port: 5432 },
      });
    });

    test("dot-separated section names create nested objects", () => {
      const input = `
[foo.bar]
baz = 1
`;
      expect(Bun.INI.parse(input)).toEqual({ foo: { bar: { baz: 1 } } });
    });

    test("semicolon comments are ignored", () => {
      expect(Bun.INI.parse("; this is a comment\nkey = value")).toEqual({ key: "value" });
    });

    test("hash comments are ignored", () => {
      expect(Bun.INI.parse("# this is a comment\nkey = value")).toEqual({ key: "value" });
    });

    test("boolean values", () => {
      expect(Bun.INI.parse("enabled = true\ndisabled = false")).toEqual({
        enabled: true,
        disabled: false,
      });
    });

    test("null value", () => {
      expect(Bun.INI.parse("x = null")).toEqual({ x: null });
    });

    test("quoted string values", () => {
      expect(Bun.INI.parse('greeting = "hello world"')).toEqual({ greeting: "hello world" });
    });

    test("array syntax with [] suffix", () => {
      const input = `
colors[] = red
colors[] = green
colors[] = blue
`;
      expect(Bun.INI.parse(input)).toEqual({ colors: ["red", "green", "blue"] });
    });

    test("empty string returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("throws on missing argument", () => {
      expect(() => (Bun.INI.parse as any)()).toThrow();
    });
  });

  describe("stringify", () => {
    test("basic key=value pairs", () => {
      const result = Bun.INI.stringify({ name: "Alice", enabled: true });
      expect(result).toContain("name = Alice");
      expect(result).toContain("enabled = true");
    });

    test("number values", () => {
      const result = Bun.INI.stringify({ port: 5432 });
      expect(result).toContain("port = 5432");
    });

    test("null value", () => {
      const result = Bun.INI.stringify({ x: null });
      expect(result).toContain("x = null");
    });

    test("nested object becomes a section", () => {
      const result = Bun.INI.stringify({ database: { host: "localhost", port: 5432 } });
      expect(result).toContain("[database]");
      expect(result).toContain("host = localhost");
      expect(result).toContain("port = 5432");
    });

    test("deeply nested object uses dot-separated section name", () => {
      const result = Bun.INI.stringify({ foo: { bar: { baz: 1 } } });
      expect(result).toContain("[foo]");
      expect(result).toContain("[foo.bar]");
      expect(result).toContain("baz = 1");
    });

    test("array values use [] suffix syntax", () => {
      const result = Bun.INI.stringify({ colors: ["red", "green", "blue"] });
      expect(result).toContain("colors[] = red");
      expect(result).toContain("colors[] = green");
      expect(result).toContain("colors[] = blue");
    });

    test("top-level scalars come before sections", () => {
      const result = Bun.INI.stringify({ name: "root", db: { host: "localhost" } });
      const namePos = result.indexOf("name = root");
      const sectionPos = result.indexOf("[db]");
      expect(namePos).toBeLessThan(sectionPos);
    });

    test("empty object produces empty string", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    test("throws on non-object", () => {
      expect(() => (Bun.INI.stringify as any)("not an object")).toThrow();
    });

    test("throws on array", () => {
      expect(() => (Bun.INI.stringify as any)(["a", "b"])).toThrow();
    });

    test("round-trip: parse(stringify(obj)) reproduces scalars", () => {
      const original = { host: "localhost", port: 5432, enabled: true };
      const ini = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(ini);
      expect(parsed).toEqual(original);
    });

    test("round-trip: parse(stringify(obj)) reproduces nested sections", () => {
      const original = { server: { host: "localhost", port: 8080 } };
      const ini = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(ini);
      expect(parsed).toEqual(original);
    });
  });
});

