pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    const bunstr = try input_value.toBunString(globalThis);
    defer bunstr.deref();
    const utf8str = bunstr.toUTF8(bun.default_allocator);
    defer utf8str.deinit();

    var parser = ini.Parser.init(
        bun.default_allocator,
        "<src>",
        utf8str.slice(),
        globalThis.bunVM().transpiler.env,
    );
    defer parser.deinit();

    try parser.parse(parser.arena.allocator());

    return parser.out.toJS(bun.default_allocator, globalThis) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        error.JSError => return error.JSError,
        error.JSTerminated => return error.JSTerminated,
        // INI parsing does not produce macros or identifiers
        else => unreachable,
    };
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input = callframe.argument(0);

    if (input.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }
    if (!input.isObject() or input.isArray()) {
        return globalThis.throwInvalidArguments("Expected a plain object to stringify", .{});
    }

    var arena = bun.ArenaAllocator.init(bun.default_allocator);
    defer arena.deinit();
    const allocator = arena.allocator();

    var output = std.ArrayList(u8).init(allocator);

    try stringifyObject(globalThis, input, "", allocator, &output);

    return bun.String.createUTF8ForJS(globalThis, output.items);
}

fn writeValue(
    globalThis: *jsc.JSGlobalObject,
    value: jsc.JSValue,
    output: *std.ArrayList(u8),
) bun.JSError!void {
    const unwrapped = try value.unwrapBoxedPrimitive(globalThis);

    if (unwrapped.isNull() or unwrapped.isUndefined()) {
        try output.appendSlice("null");
        return;
    }
    if (unwrapped.isBoolean()) {
        try output.appendSlice(if (unwrapped.asBoolean()) "true" else "false");
        return;
    }
    if (unwrapped.isInt32()) {
        var buf: [32]u8 = undefined;
        const s = std.fmt.bufPrint(&buf, "{d}", .{unwrapped.asInt32()}) catch unreachable;
        try output.appendSlice(s);
        return;
    }
    if (unwrapped.isNumber()) {
        const num = unwrapped.asNumber();
        var buf: [64]u8 = undefined;
        const s = std.fmt.bufPrint(&buf, "{d}", .{num}) catch unreachable;
        try output.appendSlice(s);
        return;
    }
    // Strings and anything else — coerce to string
    const str = try unwrapped.toBunString(globalThis);
    defer str.deref();
    const utf8 = str.toUTF8(bun.default_allocator);
    defer utf8.deinit();
    try output.appendSlice(utf8.slice());
}

fn stringifyObject(
    globalThis: *jsc.JSGlobalObject,
    obj: jsc.JSValue,
    section_prefix: []const u8,
    allocator: std.mem.Allocator,
    output: *std.ArrayList(u8),
) bun.JSError!void {
    const SectionEntry = struct {
        name: []const u8,
        value: jsc.JSValue,
    };

    var sections = std.ArrayList(SectionEntry).init(allocator);

    var iter: jsc.JSPropertyIterator(.{
        .skip_empty_name = false,
        .include_value = true,
    }) = try .init(
        globalThis,
        try obj.toObject(globalThis),
    );
    defer iter.deinit();

    while (try iter.next()) |key| {
        const value = iter.value;

        if (value.isUndefined() or value.isSymbol() or value.isFunction()) continue;

        const unwrapped = try value.unwrapBoxedPrimitive(globalThis);

        // Copy the key into the arena so it remains valid after iterator advances
        const key_utf8 = key.toUTF8(bun.default_allocator);
        defer key_utf8.deinit();
        const key_bytes = try allocator.dupe(u8, key_utf8.slice());

        if (!unwrapped.isArray() and unwrapped.isObject()) {
            // Defer this key as a section header
            try sections.append(.{ .name = key_bytes, .value = unwrapped });
            continue;
        }

        if (unwrapped.isArray()) {
            var arr_iter = try unwrapped.arrayIterator(globalThis);
            while (try arr_iter.next()) |item| {
                const item_unwrapped = try item.unwrapBoxedPrimitive(globalThis);
                // Skip nested objects inside arrays (not representable in INI)
                if (item_unwrapped.isObject() and !item_unwrapped.isArray()) continue;
                try output.appendSlice(key_bytes);
                try output.appendSlice("[] = ");
                try writeValue(globalThis, item, output);
                try output.append('\n');
            }
            continue;
        }

        // Scalar value
        try output.appendSlice(key_bytes);
        try output.appendSlice(" = ");
        try writeValue(globalThis, value, output);
        try output.append('\n');
    }

    // Write deferred sections after all scalars
    for (sections.items) |section| {
        const new_prefix: []const u8 = if (section_prefix.len == 0)
            section.name
        else
            try std.fmt.allocPrint(allocator, "{s}.{s}", .{ section_prefix, section.name });

        try output.append('\n');
        try output.append('[');
        try output.appendSlice(new_prefix);
        try output.appendSlice("]\n");

        try stringifyObject(globalThis, section.value, new_prefix, allocator, output);
    }
}

const std = @import("std");

const bun = @import("bun");
const ini = bun.ini;

const jsc = bun.jsc;
const JSValue = jsc.JSValue;
const ZigString = jsc.ZigString;

